import { PATH_ELEMENT } from '../../../../core/element-constants';
import { ORDINAL_DATATYPE } from '../../../../core/datatype-constants';
import { getSvgTransform } from '../../../../utils/svg-transforms';
import { getSVGTooltipPosition } from '../highlight-tooltip';

export function showTooltip(mouse, data) {
    let manager = this,
        { options } = manager,
        { tooltip, highlightElement, format, ranges: userRanges, isHorizontal, handles: handleOptions, dataType } = options,
        point = data.point;

    // Content
    let d = dataType === ORDINAL_DATATYPE ? userRanges[point][0] : userRanges && userRanges.length ? userRanges[point] : point[0];
    tooltip.show(format(d));

    // Position
    let handleElement = highlightElement.selectAll('g.handle--custom'),
        position;

    let pathEle = handleElement.selectAll(PATH_ELEMENT),
        pathNode = pathEle.node(),
        translate = pathNode ? getSvgTransform(pathNode).translate : [0, 0]; // TODO: check pathNode condition

    position = getSVGTooltipPosition(pathEle, tooltip.config, handleOptions ? undefined : isHorizontal, translate);
    tooltip.positionTooltip(position);
}
